class Checkers:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.turn = 'red'
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = 'r'  # Red pieces
        for row in range(5, 8):
            for col in range(row % 2, 8, 2):
                self.board[row][col] = 'b'  # Black pieces

    def print_board(self):
        for row in self.board:
            print(' '.join(['.' if cell is None else cell for cell in row]))

    def move_piece(self, from_pos, to_pos):
        piece = self.board[from_pos[0]][from_pos[1]]
        self.board[to_pos[0]][to_pos[1]] = piece
        self.board[from_pos[0]][from_pos[1]] = None

        # Handle kinging
        if piece == 'r' and to_pos[0] == 7:
            self.board[to_pos[0]][to_pos[1]] = 'R'
        elif piece == 'b' and to_pos[0] == 0:
            self.board[to_pos[0]][to_pos[1]] = 'B'

    def capture_piece(self, from_pos, middle_pos, to_pos):
        self.move_piece(from_pos, to_pos)
        piece = self.board[middle_pos[0]][middle_pos[1]]
        self.board[middle_pos[0]][middle_pos[1]] = None

    def is_valid_move(self, from_pos, to_pos):
        row_diff = abs(to_pos[0] - from_pos[0])
        col_diff = abs(to_pos[1] - from_pos[1])

        # Check if the move is within bounds
        if not (0 <= from_pos[0] < 8 and 0 <= from_pos[1] < 8 and 0 <= to_pos[0] < 8 and 0 <= to_pos[1] < 8):
            return False

        # Check if the starting position has a piece
        if self.board[from_pos[0]][from_pos[1]] is None:
            return False

        # Check if the destination position is already occupied
        if self.board[to_pos[0]][to_pos[1]] is not None:
            return False

        # Check if it's the correct player's turn
        piece = self.board[from_pos[0]][from_pos[1]]
        if (piece == 'r' and self.turn != 'red') or (piece == 'b' and self.turn != 'black'):
            return False

        # Check if the move is a valid single step
        if row_diff in [1, 2] and col_diff in [1]:
            return True

        # Check for jumps
        if row_diff == 2 and col_diff == 2:
            middle_pos = ((from_pos[0] + to_pos[0]) // 2, (from_pos[1] + to_pos[1]) // 2)
            if self.board[middle_pos[0]][middle_pos[1]] is not None and self.turn != 'b' == (self.board[from_pos[0]][from_pos[1]] in ['r', 'R']):
                return True

        return False

    def switch_turn(self):
        self.turn = 'black' if self.turn == 'red' else 'red'
